#include <iostream>
using namespace std;
bool fun(int a,int b,int c,int d)
{
    if(a%d==0&&b%d==0&&c%d==0)
    {
        return true;
    }
    return false;
}
int x(int a)
{
    return a/100;
}
int y(int a)
{
    return (a/10)%1000;
}
int z(int a)
{
    return a%1000;
}
int main()
{
    int k;
    cin>>k;
    bool flag = false;
    for(int i=10000;i<=30000;i++)
    {
        if(fun(x(i),y(i),z(i),k))
        {
            flag = true;
            cout<<i<<endl;
        }
    }
    if (!flag)
    {
        cout <<"No"<<endl;
    }
    return 0;
}
